import { uuidv7, BaseDbDriver, type DbExecuteResult } from '@motivation/shared';

type WorkerRequest = {
    type: 'db-request';
    requestId: string;
    command: string;
    payload?: unknown;
};

type WorkerResponse<T> = {
    requestId: string;
    ok: boolean;
    result?: T;
    error?: string;
};

export interface WorkerMessageTarget {
    postMessage(message: unknown, transfer?: Transferable[]): void;
}

const createRequestId = (): string => uuidv7();

export class WasmSqliteDriver extends BaseDbDriver {
    constructor(
        private readonly worker: WorkerMessageTarget,
        private readonly timeoutMs = 30000,
    ) {
        super();
    }

    async query<T>(sql: string, ...params: unknown[]): Promise<T[]> {
        return this.request<T[]>('query', { sql, params });
    }

    async execute(sql: string, ...params: unknown[]): Promise<DbExecuteResult> {
        const txnKind = this.checkTransactionPrecondition(sql);
        const result = await this.request<DbExecuteResult>('execute', { sql, params });
        this.markTransactionState(txnKind);
        return result;
    }

    request<T>(command: string, payload?: unknown, transfer: Transferable[] = []): Promise<T> {
        const requestId = createRequestId();
        const channel = new MessageChannel();

        return new Promise<T>((resolve, reject) => {
            const timer = setTimeout(() => {
                channel.port1.close();
                reject(new Error(`Worker request timed out: ${command}`));
            }, this.timeoutMs);

            channel.port1.onmessage = (event: MessageEvent<WorkerResponse<T>>) => {
                const response = event.data;
                if (!response || response.requestId !== requestId) {
                    return;
                }

                clearTimeout(timer);
                channel.port1.close();

                if (!response.ok) {
                    reject(new Error(response.error ?? `Worker request failed: ${command}`));
                    return;
                }

                resolve(response.result as T);
            };

            const message: WorkerRequest = {
                type: 'db-request',
                requestId,
                command,
                payload,
            };

            this.worker.postMessage(message, [channel.port2, ...transfer]);
        });
    }
}
