import { WasmSqliteDriver } from './wasm-sqlite.driver.js';

export type WorkerFactory = () => Worker;

const defaultWorkerFactory: WorkerFactory = () => new Worker(new URL('./db.worker.ts', import.meta.url), {
    type: 'module',
});

const PERSIST_TIMEOUT_MS = 3000;

/**
 * Resolve `promise`, or reject with a labelled timeout after `ms`. Used to cap
 * boot-critical browser calls that can hang indefinitely on PWA resume.
 */
function withTimeout<T>(promise: Promise<T>, ms: number, label: string): Promise<T> {
    return new Promise<T>((resolve, reject) => {
        const timer = setTimeout(() => reject(new Error(`${label} timed out after ${ms}ms`)), ms);
        promise.then(
            (value) => { clearTimeout(timer); resolve(value); },
            (error) => { clearTimeout(timer); reject(error); },
        );
    });
}

export class DbService {
    private static instance: DbService | null = null;

    private worker: Worker | null = null;
    private driverInstance: WasmSqliteDriver | null = null;

    constructor(
        private readonly workerFactory: WorkerFactory = defaultWorkerFactory,
        private readonly persistTimeoutMs: number = PERSIST_TIMEOUT_MS,
    ) {}

    static getInstance(): DbService {
        if (!DbService.instance) {
            DbService.instance = new DbService();
        }
        return DbService.instance;
    }

    async init(): Promise<void> {
        if (this.driverInstance) {
            console.debug('[SYNC-DEBUG][db.service] init() — already initialized, skipping');
            return;
        }

        console.debug('[SYNC-DEBUG][db.service] init() — creating worker...');
        const worker = this.workerFactory();
        this.worker = worker;
        this.driverInstance = new WasmSqliteDriver(worker);
        console.debug('[SYNC-DEBUG][db.service] init() — worker created, driver available');

        if (typeof navigator !== 'undefined' && navigator.storage?.persist) {
            // navigator.storage.persist() has been observed to hang forever on
            // PWA resume (client logs, 2026-05-30). Because boot used to start
            // the router only after DB init resolved, that hang left the route
            // outlet empty — an unrecoverable black screen. It is a best-effort
            // hint, so cap it and carry on rather than letting it stall boot.
            // See design_log #155.
            const persisted = await withTimeout(
                navigator.storage.persist(),
                this.persistTimeoutMs,
                'navigator.storage.persist()',
            ).catch((error) => {
                console.warn('[SYNC-DEBUG][db.service] storage.persist() did not settle:', error);
                return null;
            });
            console.debug('[SYNC-DEBUG][db.service] storage.persist() =', persisted);
        }
    }

    get driver(): WasmSqliteDriver {
        if (!this.driverInstance) {
            throw new Error('DbService not initialized. Call init() first.');
        }
        return this.driverInstance;
    }

    async exists(): Promise<boolean> {
        console.debug('[SYNC-DEBUG][db.service] exists() — checking...');
        const result = await this.driver.request<boolean>('db-exists');
        console.debug('[SYNC-DEBUG][db.service] exists() =', result);
        return result;
    }

    async loadFromSnapshot(buffer: ArrayBuffer): Promise<void> {
        console.debug('[SYNC-DEBUG][db.service] loadFromSnapshot() — buffer size:', buffer.byteLength);
        await this.driver.request<void>('load-snapshot', { buffer }, [buffer]);
        console.debug('[SYNC-DEBUG][db.service] loadFromSnapshot() — DONE');
    }

    async initSchema(): Promise<void> {
        console.debug('[SYNC-DEBUG][db.service] initSchema() — calling worker...');
        await this.driver.request<void>('schema-init');
        console.debug('[SYNC-DEBUG][db.service] initSchema() — DONE');
    }

    async wipe(): Promise<void> {
        console.debug('[SYNC-DEBUG][db.service] wipe() — calling worker...');
        await this.driver.request<void>('wipe');
        console.debug('[SYNC-DEBUG][db.service] wipe() — DONE');
    }

    dispose(): void {
        this.worker?.terminate();
        this.worker = null;
        this.driverInstance = null;
    }
}
